{"code": "import requests
import pandas as pd
from io import StringIO
import unittest
from unittest.mock import patch, MagicMock

def _get_num_matches(db, mzStr, adducts, tolerance=0.001):
    """Count how many unique input m/z values yield at least one match in LipidMaps."""
    mz_values = set()
    for line in mzStr.split('\n'):
        line = line.strip()
        if not line:
            continue
        try:
            mz = float(line)
            mz_values.add(mz)
        except ValueError:
            continue

    if not mz_values:
        return 0

    clean_mz = '\n'.join(str(mz) for mz in sorted(mz_values))

    url = 'https://www.lipidmaps.org/rest/compound/mass_all'
    try:
        response = requests.post(
            url,
            files={
                'mz': (None, clean_mz),
                'tolerance': (None, str(tolerance)),
                'database': (None, db),
                'adducts': (None, adducts)
            },
            timeout=60
        )
        if response.status_code != 200:
            return 0
    except requests.RequestException:
        return 0

    try:
        csv_data = StringIO(response.text)
        df = pd.read_csv(csv_data)
    except Exception:
        return 0

    if df.empty:
        return 0

    input_col = None
    possible_names = [
        'Input m/z', 'Input Mass', 'input m/z', 'input mass',
        'Input_m/z', 'input_m/z', 'Input_Mass', 'input_mass',
        'M/Z', 'm/z', 'Mass', 'mass', 'INPUT_MZ', 'INPUT_MASS'
    ]
    for col in df.columns:
        col_stripped = col.strip()
        if col_stripped in possible_names:
            input_col = col_stripped
            break

    if input_col is None:
        col_lower_map = {col.strip().lower().replace(' ', '').replace('/', '').replace('_', ''): col.strip() for col in df.columns}
        for norm_name in ['inputmz', 'inputmass', 'mz', 'mass']:
            if norm_name in col_lower_map:
                input_col = col_lower_map[norm_name]
                break

    if input_col is None:
        return 0

    matched_inputs = set()
    for val in df[input_col].dropna().unique():
        try:
            matched_inputs.add(float(val))
        except (ValueError, TypeError):
            continue

    count = 0
    for mz in mz_values:
        for matched_mz in matched_inputs:
            if abs(mz - matched_mz) <= 1e-12 * max(1.0, abs(mz)):
                count += 1
                break

    return count


class TestGetNumMatches(unittest.TestCase):
    def _mock_response(self, csv_text, status=200):
        mock_resp = MagicMock()
        mock_resp.status_code = status
        mock_resp.text = csv_text
        return mock_resp

    @patch('requests.post')
    def test_empty_match_set(self, mock_post):
        mock_post.return_value = self._mock_response('Input Mass,Matched Mass,Lipid Name\n')
        result = _get_num_matches('GLYCOLIPIDS', '100.0\n200.0', 'M+H', 0.01)
        self.assertEqual(result, 0)

    @patch('requests.post')
    def test_single_match(self, mock_post):
        mock_post.return_value = self._mock_response('Input Mass,Matched Mass,Lipid Name\n100.0,100.05,Some Lipid\n')
        result = _get_num_matches('GLYCOLIPIDS', '100.0\n200.0', 'M+H', 0.01)
        self.assertEqual(result, 1)

    @patch('requests.post')
    def test_all_match(self, mock_post):
        mock_post.return_value = self._mock_response('Input Mass,Matched Mass,Lipid Name\n100.0,100.05,Lipid A\n200.0,200.05,Lipid B\n')
        result = _get_num_matches('GLYCOLIPIDS', '100.0\n200.0', 'M+H', 0.01)
        self.assertEqual(result, 2)

    @patch('requests.post')
    def test_variable_column_name(self, mock_post):
        mock_post.return_value = self._mock_response('Input m/z,Matched Mass,Lipid Name\n100.0,100.05,Lipid A\n')
        result = _get_num_matches('GLYCOLIPIDS', '100.0\n200.0', 'M+H', 0.01)
        self.assertEqual(result, 1)

    @patch('requests.post')
    def test_malformed_input(self, mock_post):
        mock_post.return_value = self._mock_response('Input Mass,Matched Mass,Lipid Name\n100.0,100.05,Lipid A\n')
        result = _get_num_matches('GLYCOLIPIDS', '\n\n100.0\nabc\n\n', 'M+H', 0.01)
        self.assertEqual(result, 1)

    @patch('requests.post')
    def test_no_valid_input(self, mock_post):
        result = _get_num_matches('GLYCOLIPIDS', 'abc\ndef\n\n', 'M+H', 0.01)
        self.assertEqual(result, 0)

if __name__ == '__main__':
    suite = unittest.TestLoader().loadTestsFromTestCase(TestGetNumMatches)
    runner = unittest.TextTestRunner(verbosity=2)
    runner.run(suite)
